const bootstrap={};
bootstrap.Modal=class{constructor(el){this.el=el;}show(){this.el.classList.add('show');}hide(){this.el.classList.remove('show');}}
bootstrap.Modal.getInstance=el=>new bootstrap.Modal(el);
bootstrap.Tab=class{constructor(el){this.el=el;}show(){const target=this.el.getAttribute('data-bs-target');if(target){document.querySelectorAll('.tab-pane').forEach(p=>p.classList.remove('show','active'));const pane=document.querySelector(target);if(pane)pane.classList.add('show','active');}this.el.parentElement.querySelectorAll('.nav-link').forEach(l=>l.classList.remove('active'));this.el.classList.add('active');}};
